 227→function handleChallenge(
 228→  raw: Uint8Array,
 229→  config: ClientConfig,
 230→  srp: SRP,
 231→): SRPResult {
 232→  const r = new PacketReader(raw);
 233→  r.skip(1);
 234→  const result = parseLogonChallengeResponse(r);
 235→  if (result.status !== 0x00) {
 236→    throw new Error(
 237→      `Auth challenge failed: status 0x${result.status.toString(16)}`,
 238→    );
 239→  }
 240→  return srp.calculate(
 241→    result.g!,
 242→    result.N!,
 243→    result.salt!,
 244→    result.B!,
 245→    config.srpPrivateKey,
 246→  );
 247→}
