 253→  if (result.status !== 0x00) {
 254→    throw new Error(
 255→      `Auth proof failed: status 0x${result.status.toString(16)}`,
 256→    );
 257→  }
 258→  if (result.M2 !== srpResult.M2) throw new Error("Server M2 mismatch");
 259→}
