 416→function drainWorldPackets(conn: WorldConn): void {
 417→  while (true) {
 418→    if (!conn.pendingHeader) {
 419→      if (conn.buf.length < INCOMING_HEADER_SIZE) break;
 420→      conn.pendingHeader = decryptIncomingHeader(
 421→        conn.buf.drain(INCOMING_HEADER_SIZE),
 422→        conn.arc4,
 423→      );
 424→    }
 425→    const bodySize = conn.pendingHeader.size - 2;
 426→    if (conn.buf.length < bodySize) break;
 427→
 428→    const { opcode } = conn.pendingHeader;
 429→    conn.pendingHeader = undefined;
 430→    try {
 431→      conn.dispatch.handle(opcode, new PacketReader(conn.buf.drain(bodySize)));
 432→    } catch (err) {
 433→      if (err instanceof Error) {
 434→        conn.onPacketError?.(opcode, err);
 435→      }
 436→    }
 437→  }
 438→}
