 507→function handleNameQueryResponse(conn: WorldConn, r: PacketReader): void {
 508→  const result = parseNameQueryResponse(r);
 509→
 510→  const name = result.found && result.name ? result.name : "";
 511→  conn.pendingNameQueries.delete(`player:${result.guidLow}`);
 512→  if (result.found && result.name) {
 513→    conn.nameCache.set(result.guidLow, result.name);
 514→    for (const entity of conn.entityStore.all()) {
 515→      if (
 516→        entity.objectType === ObjectType.PLAYER &&
 517→        Number(entity.guid & 0xffffffffn) === result.guidLow &&
 518→        !entity.name
 519→      ) {
 520→        conn.entityStore.setName(entity.guid, result.name);
 521→      }
 522→    }
 523→    for (const friend of conn.friendStore.all()) {
 524→      if (
 525→        Number(friend.guid & 0xffffffffn) === result.guidLow &&
 526→        !friend.name
 527→      ) {
 528→        conn.friendStore.setName(friend.guid, result.name);
 529→      }
 530→    }
 531→  }
 532→
 533→  const pending = conn.pendingMessages.get(result.guidLow);
 534→  if (!pending) return;
 535→  for (const raw of pending) deliverMessage(conn, raw, name);
 536→  conn.pendingMessages.delete(result.guidLow);
 537→}
