 539→function handleChannelNotify(conn: WorldConn, r: PacketReader): void {
 540→  const event = parseChannelNotify(r);
 541→  if (event.type === "joined") {
 542→    conn.channels.push(event.channel);
 543→  } else if (event.type === "left") {
 544→    const idx = conn.channels.indexOf(event.channel);
 545→    if (idx !== -1) conn.channels.splice(idx, 1);
 546→  }
 547→}
