 864→function handleFriendStatus(conn: WorldConn, r: PacketReader): void {
 865→  const packet = parseFriendStatus(r);
 866→  const guidLow = Number(packet.guid & 0xffffffffn);
 867→
 868→  switch (packet.result) {
 869→    case FriendResult.ADDED_ONLINE:
 870→    case FriendResult.ADDED_OFFLINE: {
 871→      const name = conn.nameCache.get(guidLow) ?? "";
 872→      conn.friendStore.add({
 873→        guid: packet.guid,
 874→        name,
 875→        note: packet.note ?? "",
 876→        status: packet.status ?? 0,
 877→        area: packet.area ?? 0,
 878→        level: packet.level ?? 0,
 879→        playerClass: packet.playerClass ?? 0,
 880→      });
 881→      if (!name && !conn.pendingNameQueries.has(`player:${guidLow}`)) {
 882→        conn.pendingNameQueries.add(`player:${guidLow}`);
 883→        sendPacket(
 884→          conn,
 885→          GameOpcode.CMSG_NAME_QUERY,
 886→          buildNameQuery(guidLow, Number((packet.guid >> 32n) & 0xffffffffn)),
 887→        );
 888→      }
 889→      break;
 890→    }
 891→    case FriendResult.ONLINE:
 892→      conn.friendStore.update(packet.guid, {
 893→        status: packet.status ?? FriendStatus.ONLINE,
 894→        area: packet.area ?? 0,
 895→        level: packet.level ?? 0,
 896→        playerClass: packet.playerClass ?? 0,
 897→      });
 898→      break;
 899→    case FriendResult.OFFLINE:
 900→      conn.friendStore.update(packet.guid, { status: FriendStatus.OFFLINE });
 901→      break;
 902→    case FriendResult.REMOVED:
 903→      conn.friendStore.remove(packet.guid);
 904→      break;
 905→    default: {
 906→      const name = conn.nameCache.get(guidLow) ?? `guid:${guidLow}`;
 907→      conn.onFriendEvent?.({
 908→        type: "friend-error",
 909→        result: packet.result,
 910→        name,
 911→      });
 912→      break;
 913→    }
 914→  }
 915→}
