 917→async function authenticateWorld(
 918→  conn: WorldConn,
 919→  config: ClientConfig,
 920→  auth: AuthResult,
 921→): Promise<void> {
 922→  const challenge = await conn.dispatch.expect(GameOpcode.SMSG_AUTH_CHALLENGE);
 923→  challenge.uint32LE();
 924→  const serverSeed = challenge.bytes(4);
 925→
 926→  const body = await buildWorldAuthPacket(
 927→    config.account,
 928→    auth.sessionKey,
 929→    serverSeed,
 930→    auth.realmId,
 931→    config.clientSeed,
 932→  );
 933→  conn.socket.write(buildOutgoingPacket(GameOpcode.CMSG_AUTH_SESSION, body));
 934→  conn.arc4 = new Arc4(auth.sessionKey);
 935→
 936→  const resp = await conn.dispatch.expect(GameOpcode.SMSG_AUTH_RESPONSE);
 937→  const status = resp.uint8();
 938→  if (status !== 0x0c) {
 939→    const names: Record<number, string> = {
 940→      0x0d: "system error",
 941→      0x15: "account in use",
 942→    };
 943→    const label = names[status] ?? `status 0x${status.toString(16)}`;
 944→    throw new Error(`World auth failed: ${label}`);
 945→  }
 946→}
