513→export type TuiState = {
514→  handle: WorldHandle;
515→  write: (s: string) => void;
516→  lastWhisperFrom: string | undefined;
517→  showEntityEvents: boolean;
518→};
519→
520→export async function executeCommand(
521→  state: TuiState,
522→  cmd: Command,
523→): Promise<boolean> {
524→  switch (cmd.type) {
525→    case "chat":
526→      state.handle.sendInCurrentMode(cmd.message);
527→      break;
528→    case "say":
529→      state.handle.sendSay(cmd.message);
530→      break;
531→    case "yell":
532→      state.handle.sendYell(cmd.message);
533→      break;
534→    case "guild":
535→      state.handle.sendGuild(cmd.message);
536→      break;
537→    case "party":
538→      state.handle.sendParty(cmd.message);
539→      break;
540→    case "raid":
541→      state.handle.sendRaid(cmd.message);
542→      break;
543→    case "emote":
544→      state.handle.sendEmote(cmd.message);
545→      break;
546→    case "dnd":
547→      state.handle.sendDnd(cmd.message);
548→      break;
549→    case "afk":
550→      state.handle.sendAfk(cmd.message);
551→      break;
552→    case "whisper":
553→      state.handle.sendWhisper(cmd.target, cmd.message);
554→      state.lastWhisperFrom = cmd.target;
555→      break;
556→    case "reply":
557→      if (!state.lastWhisperFrom) {
558→        state.write(formatError("No one has whispered you yet.") + "\n");
559→      } else {
560→        state.handle.sendWhisper(state.lastWhisperFrom, cmd.message);
561→      }
562→      break;
563→    case "channel": {
564→      const channel = /^\d+$/.test(cmd.target)
565→        ? state.handle.getChannel(parseInt(cmd.target, 10))
566→        : cmd.target;
567→      if (!channel) {
568→        state.write(formatError(`Not in channel ${cmd.target}.`) + "\n");
569→      } else {
570→        state.handle.sendChannel(channel, cmd.message);
571→      }
572→      break;
573→    }
574→    case "who": {
575→      const results = await state.handle.who(
576→        cmd.target ? { name: cmd.target } : {},
577→      );
578→      state.write(formatWhoResults(results) + "\n");
579→      break;
580→    }
581→    case "invite":
582→      state.handle.invite(cmd.target);
583→      break;
584→    case "kick":
585→      state.handle.uninvite(cmd.target);
586→      break;
587→    case "leave":
588→      state.handle.leaveGroup();
589→      break;
590→    case "leader":
591→      state.handle.setLeader(cmd.target);
592→      break;
593→    case "accept":
594→      state.handle.acceptInvite();
595→      break;
596→    case "decline":
597→      state.handle.declineInvite();
598→      break;
599→    case "quit":
600→      return true;
601→    case "tuicraft":
602→      if (cmd.subcommand === "entities") {
603→        if (cmd.value === "on") {
604→          state.showEntityEvents = true;
605→          state.write("[system] Entity events enabled\n");
606→        } else if (cmd.value === "off") {
607→          state.showEntityEvents = false;
608→          state.write("[system] Entity events disabled\n");
609→        } else {
610→          state.write("[system] Usage: /tuicraft entities on|off\n");
611→        }
612→      } else {
613→        state.write(`[system] Unknown tuicraft command: ${cmd.subcommand}\n`);
614→      }
615→      break;
616→    case "friends": {
617→      const friends = state.handle.getFriends();
618→      state.write(formatFriendList(friends) + "\n");
619→      break;
620→    }
621→    case "add-friend":
622→      state.handle.addFriend(cmd.target);
623→      break;
624→    case "remove-friend":
625→      state.handle.removeFriend(cmd.target);
626→      break;
627→    case "roll":
628→      state.handle.sendRoll(cmd.min, cmd.max);
629→      break;
630→    case "unimplemented":
631→      state.write(formatError(`${cmd.feature} is not yet implemented`) + "\n");
632→      break;
633→  }
634→  return false;
635→}
636→
637→export type TuiOptions = {
638→  input?: NodeJS.ReadableStream;
639→  write?: (s: string) => void;
640→};
641→
642→export function startTui(
643→  handle: WorldHandle,
644→  interactive: boolean,
645→  opts: TuiOptions = {},
646→): Promise<void> {
647→  const write = opts.write ?? ((s: string) => void process.stdout.write(s));
648→  const state: TuiState = {
649→    handle,
650→    write,
651→    lastWhisperFrom: undefined,
652→    showEntityEvents: false,
653→  };
654→
655→  return new Promise<void>((resolve) => {
656→    handle.onMessage((msg) => {
657→      if (msg.type === ChatType.WHISPER) state.lastWhisperFrom = msg.sender;
658→      const line = formatMessage(msg);
659→      write(interactive ? `\r\x1b[K${line}\n` : line + "\n");
660→      if (interactive) rl.prompt(true);
661→    });
662→
663→    handle.onGroupEvent((event) => {
664→      const line = formatGroupEvent(event);
665→      if (!line) return;
666→      write(interactive ? `\r\x1b[K${line}\n` : line + "\n");
667→      if (interactive) rl.prompt(true);
668→    });
669→
670→    handle.onEntityEvent((event) => {
671→      if (!state.showEntityEvents) return;
672→      const line = formatEntityEvent(event);
673→      if (!line) return;
674→      write(interactive ? `\r\x1b[K${line}\n` : line + "\n");
