        expect(friends[0]!.status).toBe(1);
        expect(friends[0]!.area).toBe(1519);
        expect(friends[0]!.level).toBe(80);
        expect(friends[0]!.playerClass).toBe(1);
        expect(friends[0]!.note).toBe("best buddy");

        handle.close();
        await handle.closed;
      } finally {
        ws.stop();
      }
    });

