+In `src/wow/client.ts:108-113`, add `origin` to the public ChatMessage type:
+
+```typescript
+export type ChatMessage = {
+  type: number;
+  sender: string;
+  message: string;
+  channel?: string;
+  origin?: "server" | "notification";
+};
+```
