+export function parseServerBroadcast(r: PacketReader): { message: string } {
+  const messageId = r.uint32LE();
+  const param = r.cString();
+  const fmt = SERVER_MESSAGES[messageId];
+  const message =
+    typeof fmt === "function"
+      ? fmt(param)
+      : `Server message ${messageId}: ${param}`;
+  return { message };
+}
